  state.connections=structuredClone(project?.connections??defaultConnections.filter(connection=>!["TXT_00","TXT_BRAND"].some(nodeId=>connection.includes(nodeId))));
  state.textureNodes=structuredClone(project?.textureNodes??defaultTextureNodes);state.textureConnections=structuredClone(project?.textureConnections??defaultTextureConnections);
  state.postNodes=structuredClone(project?.postNodes??defaultPostNodes);state.postConnections=structuredClone(project?.postConnections??defaultPostConnections);
  state.audioNodes=structuredClone(project?.audioNodes??defaultAudioNodes);state.audioConnections=structuredClone(project?.audioConnections??defaultAudioConnections);
  state.params={...defaults,...demo.params,...project?.params};state.audio={enabled:false,volume:project?.audio?.volume??.42};state.bpm=project?.bpm??demo.bpm;state.duration=project?.duration??12;state.showcase=project?.showcase??false;state.visualMode=project?.visualMode??"default";state.sceneVersion=DEFAULT_SCENE_VERSION;state.time=0;state.zoom=1;state.selected=project?.selected??"MAT_04";graphPan={x:0,y:0};
